import React, { useState, useEffect } from 'react';
import {
  Paper,
  Typography,
  Box,
  Skeleton,
  useTheme,
  Divider,
  TextField,
  Button,
  Grid,
  Card,
  CardContent,
  Collapse,
  IconButton
} from '@mui/material';
import {
  ShowChart,
  Timeline,
  TrendingUp,
  FilterList,
  ExpandMore,
  ExpandLess
} from '@mui/icons-material';
import dashboardService from '../../services/dashboardService';

const ConsolidatedStatsCard = ({ hideValues = false }) => {
  const theme = useTheme();
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [openPositions, setOpenPositions] = useState([]);
  const [closedTrades, setClosedTrades] = useState([]);
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [showFilters, setShowFilters] = useState(false);
  const [initialLoad, setInitialLoad] = useState(true);

  // Carregar dados do dashboard
  useEffect(() => {
    const loadStats = async (showLoading = true) => {
      try {
        if (showLoading && initialLoad) {
          setLoading(true);
        }
        const [statsResponse, openPositionsResponse, closedTradesResponse] = await Promise.all([
          dashboardService.getUserStats(startDate, endDate),
          dashboardService.getOpenPositions(),
          dashboardService.getClosedTrades()
        ]);

        const statsData = statsResponse.data || statsResponse;
        const openPositionsData = openPositionsResponse.data || [];
        const closedTradesData = closedTradesResponse.data || [];

        setOpenPositions(openPositionsData);
        setClosedTrades(closedTradesData);
        setStats(statsData);

        // Marcar que o carregamento inicial foi concluído
        if (initialLoad) {
          setInitialLoad(false);
        }
      } catch (error) {
        console.error('Erro ao carregar estatísticas:', error);
        setStats(null);
      } finally {
        if (showLoading && initialLoad) {
          setLoading(false);
        }
      }
    };

    // Carregar dados (com ou sem loading dependendo se é inicial ou filtro)
    loadStats(initialLoad);

    // Timer para atualização automática a cada 30 segundos (sem loading)
    const interval = setInterval(() => {
      if (!initialLoad) { // Só inicia o timer após carregamento inicial
        loadStats(false);
      }
    }, 30000);

    return () => clearInterval(interval);
  }, [startDate, endDate, initialLoad]); // Incluindo as dependências de volta

  // Função para limpar filtros
  const clearFilters = () => {
    setStartDate('');
    setEndDate('');
  };

  const formatCurrency = (value, respectHideValues = true) => {
    if (respectHideValues && hideValues) return '$***';
    if (value === null || value === undefined) return '$0.00';
    const numValue = parseFloat(value);

    if (Math.abs(numValue) < 0.001 && numValue !== 0) {
      return `$${numValue.toFixed(8)}`;
    }
    if (Math.abs(numValue) < 0.1 && numValue !== 0) {
      return `$${numValue.toFixed(6)}`;
    }
    if (Math.abs(numValue) < 1) {
      return `$${numValue.toFixed(4)}`;
    }
    return `$${numValue.toFixed(2)}`;
  };

  const formatPercentage = (value, respectHideValues = true) => {
    if (respectHideValues && hideValues) return '***%';
    if (value === null || value === undefined) return '0%';

    if (Math.abs(value) < 0.01 && value !== 0) {
      return `${value >= 0 ? '+' : ''}${value.toFixed(6)}%`;
    }
    if (Math.abs(value) < 1) {
      return `${value >= 0 ? '+' : ''}${value.toFixed(4)}%`;
    }
    return `${value >= 0 ? '+' : ''}${value.toFixed(2)}%`;
  };

  const getColorByValue = (value) => {
    if (value > 0) return theme.palette.success.main;
    if (value < 0) return theme.palette.error.main;
    return theme.palette.text.secondary;
  };

  // Usar dados das estatísticas do backend (que já calculam baseado na Bitget)
  const getRealizedProfit = () => {
    // Usar dados do backend que busca da Bitget
    return stats?.realized_pnl || 0;
  };

  // Usar taxa de acerto das estatísticas do backend
  const getWinRate = () => {
    // Usar dados do backend que calcula baseado na Bitget
    return stats?.win_rate || 0;
  };

  // Calcular ROE das posições abertas
  const calculateOpenROE = () => {
    if (!openPositions || openPositions.length === 0) return 0;

    let totalROE = 0;

    openPositions.forEach(position => {
      let positionROE = 0;

      if (position.roe !== undefined && position.roe !== null) {
        positionROE = parseFloat(position.roe || 0);
      } else {
        const margin = parseFloat(position.margin_size || position.margin || 0);
        const pnl = parseFloat(position.unrealized_pnl || 0);

        if (margin > 0) {
          positionROE = (pnl / margin) * 100;
        }
      }

      totalROE += positionROE;
    });

    return totalROE;
  };

  const realizedProfit = getRealizedProfit();
  const winRate = getWinRate();
  const openROE = calculateOpenROE();

  // Debug: verificar dados carregados
  console.log('Stats from backend:', stats);
  console.log('Realized profit from stats:', realizedProfit);
  console.log('Win rate from stats:', winRate);

  if (loading) {
    return (
      <Paper sx={{ p: 2.5, height: 320 }}>
        <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 2, fontSize: '1.1rem' }}>
          📊 Estatísticas de Trading
        </Typography>
        <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
          <Skeleton variant="rectangular" height={60} />
          <Skeleton variant="rectangular" height={60} />
          <Skeleton variant="rectangular" height={60} />
        </Box>
      </Paper>
    );
  }

  return (
    <Paper sx={{ p: 2.5, height: 'auto', minHeight: 320, transition: 'all 0.3s ease-in-out' }}>
      {/* Cabeçalho */}
      <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 2 }}>
        <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1, fontSize: '1.1rem' }}>
          📊 Estatísticas de Trading
        </Typography>
        <IconButton 
          onClick={() => setShowFilters(!showFilters)}
          size="small"
          sx={{ color: theme.palette.primary.main }}
        >
          <FilterList />
          {showFilters ? <ExpandLess /> : <ExpandMore />}
        </IconButton>
      </Box>

      {/* Filtros de Data */}
      <Collapse in={showFilters}>
        <Card sx={{ mb: 2, bgcolor: 'background.default' }}>
          <CardContent sx={{ p: 1.5, '&:last-child': { pb: 1.5 } }}>
            <Grid container spacing={1.5}>
              <Grid item xs={12} md={4}>
                <TextField
                  label="Data Inicial"
                  type="date"
                  value={startDate}
                  onChange={(e) => setStartDate(e.target.value)}
                  InputLabelProps={{
                    shrink: true,
                  }}
                  fullWidth
                  size="small"
                />
              </Grid>
              <Grid item xs={12} md={4}>
                <TextField
                  label="Data Final"
                  type="date"
                  value={endDate}
                  onChange={(e) => setEndDate(e.target.value)}
                  InputLabelProps={{
                    shrink: true,
                  }}
                  fullWidth
                  size="small"
                />
              </Grid>
              <Grid item xs={12} md={4}>
                <Button
                  variant="outlined"
                  onClick={clearFilters}
                  fullWidth
                  size="small"
                >
                  Limpar Filtros
                </Button>
              </Grid>
            </Grid>
            <Typography variant="caption" sx={{ color: 'text.secondary', mt: 1, display: 'block' }}>
              * Sem filtro = mês atual. Com filtro = período personalizado para o Lucro Realizado.
            </Typography>
          </CardContent>
        </Card>
      </Collapse>

      {/* Conteúdo */}
      <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>

        {/* Lucro Realizado */}
        <Box sx={{ 
          display: 'flex', 
          alignItems: 'center', 
          justifyContent: 'space-between',
          p: 1.5,
          bgcolor: 'background.default',
          borderRadius: 1,
          border: `1px solid ${theme.palette.divider}`
        }}>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
            <Timeline sx={{ color: getColorByValue(realizedProfit), fontSize: 20 }} />
            <Typography variant="body1" sx={{ fontWeight: 500 }}>
              Lucro Realizado
            </Typography>
          </Box>
          <Typography 
            variant="h6" 
            sx={{ 
              fontWeight: 'bold',
              color: getColorByValue(realizedProfit)
            }}
          >
            {realizedProfit >= 0 ? '+' : ''}{formatCurrency(realizedProfit, true)}
          </Typography>
        </Box>

        <Divider sx={{ my: 0.5 }} />

        {/* ROE Aberto */}
        <Box sx={{ 
          display: 'flex', 
          alignItems: 'center', 
          justifyContent: 'space-between',
          p: 1.5,
          bgcolor: 'background.default',
          borderRadius: 1,
          border: `1px solid ${theme.palette.divider}`
        }}>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
            <ShowChart sx={{ color: getColorByValue(openROE || 0), fontSize: 20 }} />
            <Typography variant="body1" sx={{ fontWeight: 500 }}>
              ROE Aberto =
            </Typography>
          </Box>
          <Typography 
            variant="h6" 
            sx={{ 
              fontWeight: 'bold',
              color: getColorByValue(openROE || 0)
            }}
          >
            {formatPercentage(openROE, false)}
          </Typography>
        </Box>

        <Divider sx={{ my: 0.5 }} />

        {/* Taxa de Acerto */}
        <Box sx={{ 
          display: 'flex', 
          alignItems: 'center', 
          justifyContent: 'space-between',
          p: 1.5,
          bgcolor: 'background.default',
          borderRadius: 1,
          border: `1px solid ${theme.palette.divider}`
        }}>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
            <TrendingUp sx={{ color: getColorByValue(winRate), fontSize: 20 }} />
            <Typography variant="body1" sx={{ fontWeight: 500 }}>
              Taxa de Acerto
            </Typography>
          </Box>
          <Typography 
            variant="h6" 
            sx={{ 
              fontWeight: 'bold',
              color: getColorByValue(winRate)
            }}
          >
            {formatPercentage(winRate, false)}
          </Typography>
        </Box>

        {/* Informação adicional */}
        <Box sx={{ mt: 'auto', pt: 1 }}>
          <Typography variant="caption" color="text.secondary" align="center" display="block">
            Atualizado automaticamente a cada 30 segundos
          </Typography>
        </Box>
      </Box>
    </Paper>
  );
};

export default ConsolidatedStatsCard;
